echo "timestamp,unified_mem_mb,swap_mb,power_w,gpu_util_percent,cpu_percent" > hardware_log.csv; while true; do echo "$(date '+%Y/%m/%d %H:%M:%S'),$(LC_ALL=C free -m | awk '/^Mem:/ {print $3}'),$(LC_ALL=C free -m | awk '/^Swap:/ {print $3}'),$(nvidia-smi --query-gpu=power.draw,utilization.gpu --format=csv,noheader,nounits | tr -d ' '),$(LC_ALL=C vmstat 1 2 | tail -1 | awk '{print 100-$15}')" >> hardware_log.csv; done
